        $db_s_path = $ws . '/' . $db_s;

        if (!file_exists($db_p_path)) return ['error' => "Primary DB not found: {$db_p}"];
        if (!file_exists($db_s_path)) return ['error' => "Secondary DB not found: {$db_s}"];

