                    FROM {$safe_tbl_p} {$join_type} JOIN {$safe_tbl_s} 
                    ON {$safe_tbl_p}.{$safe_col_p} = {$safe_tbl_s}.{$safe_col_s}";
            
            if ($max_rows > 0) $sql .= " LIMIT {$max_rows}";
            
            $stmt = $pdo->query($sql);
            $rows = $stmt->fetchAll(PDO::FETCH_ASSOC);
            
            $result = [
